const handleIframeLoad = (e) => {
    console.log("[IFRAME] Content Loaded");
    const iframe = e.target;
    iframeRef.current = iframe;

    // Small delay to ensure the blob document is fully parsed by the browser
    setTimeout(() => {
        try {
            const doc = iframe.contentDocument || iframe.contentWindow.document;
            if (!doc) return;

            const docBody = doc.body;
            const docEl = doc.documentElement;

            // Standardize the iframe internal layout
            docBody.style.margin = '0';
            docBody.style.padding = '0';
            docBody.style.overflow = 'hidden';

            // Measure the actual full content size - MOVE THIS UP TO AVOID REFERENCE ERROR
            const w = Math.max(docBody.scrollWidth, docBody.offsetWidth, docEl.clientWidth, docEl.scrollWidth);
            const h = Math.max(docBody.scrollHeight, docBody.offsetHeight, docEl.clientHeight, docEl.scrollHeight);

            // --- DOCUMENT-RELATIVE SCALING ---
            // We no longer divide by fitScale. By using a fixed size (e.g. 22px),
            // the question text will scale proportionally with the book's native text
            // through the iframe's CSS transform scale.
            const baseFontSize = 22; 

            const style = doc.createElement('style');
            style.textContent = `
                @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@500;700&display=swap');

                /* --- THEME ENGINE --- */
                body { 
                    transition: background-color 0.3s ease, color 0.3s ease; 
                    min-width: ${w}px; /* Prevent body collapse */
                }

                /* Dark Theme */
                body.theme-dark, 
                body.theme-dark .page, 
                body.theme-dark .page-container, 
                body.theme-dark .text-container {
                    background-color: #121212 !important;
                    color: #d0d0d0 !important;
                }
                body.theme-dark span, 
                body.theme-dark p, 
                body.theme-dark div {
                    color: #d0d0d0 !important;
                    background-color: transparent !important;
                }
                body.theme-dark img { opacity: 0.85; mix-blend-mode: normal; }

                /* Sepia Theme */
                body.theme-sepia, 
                body.theme-sepia .page, 
                body.theme-sepia .page-container {
                    background-color: #f4ecd8 !important;
                    color: #5b4636 !important;
                }
                body.theme-sepia span, 
                body.theme-sepia p {
                    color: #5b4636 !important;
                    background-color: transparent !important;
                }
                body.theme-sepia .q-label { color: #8a6a4b !important; }
                body.theme-sepia .miron-orb-mini { background: #8a6a4b !important; }
                body.theme-sepia .q-opt-btn { background: rgba(91, 70, 54, 0.05) !important; border-color: rgba(91, 70, 54, 0.15) !important; color: #5b4636 !important; }
                body.theme-sepia .q-submit { background: #8a6a4b !important; color: #f4ecd8 !important; }
                body.theme-sepia .q-match-item {
                    background: rgba(91, 70, 54, 0.05) !important;
                    border-color: rgba(91, 70, 54, 0.2) !important;
                    color: #5b4636 !important;
                }
                body.theme-sepia .q-column-b .q-match-item {
                    background: rgba(138, 106, 75, 0.1) !important;
                    border-color: #8a6a4b !important;
                }

                                    /* The Root Container sets the Base Font Size */
                .miron-portal-container {
                    /* Matches common book padding logic to align with text edges */
                    width: 100%;
                    max-width: 100%;
                    margin: 2.5em 0;
                    font-family: 'Poppins', sans-serif;
                    font-size: ${baseFontSize}px; 
                    position: relative;
                    z-index: 100;
                    box-sizing: border-box;
                }

                /* All children use 'em' to scale relative to the dynamic base */
                .miron-question-card {
                    background: transparent;
                    border: none;
                    border-radius: 0;
                    padding: 0;
                    box-shadow: none;
                    color: inherit;
                }
                .q-header {
                    display: flex;
                    align-items: center;
                    margin-bottom: 1.5em;
                    gap: 0.75em;
                }
                .miron-orb-mini {
                    width: 1em;
                    height: 1em;
                    background: #42d7b8;
                    border-radius: 50%;
                    box-shadow: 0 0 0.8em rgba(66, 215, 184, 0.6);
                }
                .q-label {
                    color: #42d7b8;
                    font-weight: 700;
                    letter-spacing: 0.1em;
                    font-size: 0.85em; 
                    text-transform: uppercase;
                }
                .q-points-badge {
                    margin-left: auto;
                    font-size: 0.75em;
                    opacity: 0.6;
                    font-family: monospace;
                }
                .q-source-attribution {
                    font-size: 0.65em;
                    color: #888;
                    margin-bottom: 0.5em;
                    text-transform: uppercase;
                    letter-spacing: 0.05em;
                    font-weight: 500;
                    display: flex;
                    align-items: center;
                    gap: 0.5em;
                }
                .q-source-attribution i {
                    font-size: 1.1em;
                    color: #42d7b8;
                    opacity: 0.7;
                }
                body.theme-sepia .q-source-attribution { color: #8a6a4b; opacity: 0.8; }
                body.theme-sepia .q-source-attribution i { color: #5b4636; }
                .q-text {
                    font-family: serif; /* Force inheritance of book's primary font */
                    font-size: 1.25em; 
                    line-height: 1.5;
                    margin-bottom: 1.2em;
                    font-weight: 600;
                }
                .q-media-content {
                    width: 100%;
                    border-radius: 1em;
                    margin-bottom: 1.5em;
                    border: 1px solid rgba(255,255,255,0.1);
                    display: block;
                }
                /* Matching Layout */
                .q-matching-container {
                    display: grid;
                    grid-template-columns: 1fr 1fr;
                    gap: 1em;
                    margin-bottom: 1.5em;
                }
                .q-match-column {
                    display: flex;
                    flex-direction: column;
                    gap: 0.6em;
                }
                .q-match-item {
                    padding: 0.8em 1em;
                    border-radius: 0.6em;
                    font-size: 0.9em;
                    background: rgba(255,255,255,0.03);
                    border: 1px dashed rgba(255,255,255,0.1);
                    min-height: 3em;
                    display: flex;
                    align-items: center;
                }
                .q-column-b .q-match-item {
                    border-style: solid;
                    border-color: rgba(66, 215, 184, 0.2);
                    background: rgba(66, 215, 184, 0.02);
                }
                .q-options {
                    display: grid;
                    grid-template-columns: 1fr 1fr;
                    gap: 0.75em;
                }
                .q-options.vertical-layout {
                    grid-template-columns: 1fr;
                }
                .q-opt-btn {
                    background: rgba(255,255,255,0.04);
                    border: 1px solid rgba(255,255,255,0.1);
                    padding: 0.8em 1em;
                    border-radius: 0.8em;
                    color: #fff;
                    font-size: 0.95em;
                    font-family: inherit;
                    text-align: left;
                    cursor: pointer;
                    transition: all 0.2s;
                    display: flex;
                    align-items: center;
                    gap: 0.8em;
                }
                .q-opt-btn.selected {
                    background: rgba(66, 215, 184, 0.15);
                    border-color: #42d7b8;
                    border-width: 2px;
                    box-shadow: 0 4px 20px rgba(66, 215, 184, 0.2), inset 0 0 10px rgba(66, 215, 184, 0.1);
                    transform: translateY(-2px);
                }
                .opt-indicator {
                    width: 1.1em;
                    height: 1.1em;
                    border-radius: 50%;
                    border: 2px solid rgba(255,255,255,0.2);
                    flex-shrink: 0;
                    transition: all 0.25s cubic-bezier(0.175, 0.885, 0.32, 1.275);
                }
                .q-opt-btn.selected .opt-indicator {
                    border-color: #42d7b8;
                    background: #42d7b8;
                    box-shadow: 0 0 12px #42d7b8;
                    transform: scale(1.1);
                }
                .q-submit {
                    display: none; /* Initially hidden */
                    margin: 2.5em auto 0;
                    padding: 0.8em 2.5em;
                    background: rgba(66, 215, 184, 0.05);
                    color: #42d7b8;
                    font-weight: 700;
                    font-size: 0.85em;
                    font-family: inherit;
                    border: 1px solid rgba(66, 215, 184, 0.5);
                    border-radius: 99px;
                    cursor: pointer;
                    text-transform: uppercase;
                    letter-spacing: 1px;
                    animation: mironBloom 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
                }
                /* CSS Failsafe: Show button if any sibling option has the selected class */
                .miron-question-card:has(.selected) .q-submit {
                    display: block !important;
                }
                @keyframes mironBloom {
                    from { opacity: 0; transform: translateY(15px) scale(0.8); }
                    to { opacity: 1; transform: translateY(0) scale(1); }
                }
                .q-submit.success {
                    background: #b1d34b;
                    border-color: #b1d34b;
                    color: #0c0c0c;
                    box-shadow: 0 0 20px rgba(177, 211, 75, 0.4);
                }

                /* --- SMART HIGHLIGHT --- */
                ::highlight(sentence-focus) {
                    background-color: #fde047;
                    color: #000;
                }
            `;
            doc.head.appendChild(style);

            // Apply initial theme
            doc.body.className = `theme-${currentTheme}`;

            contentDims.current = { width: w, height: h };

            // Hydrate Miron Challenges from Data Anchors
            doc.querySelectorAll('.miron-challenge-anchor').forEach(anchor => {
                try {
                    const rawData = anchor.getAttribute('data-questions');
                    const questions = JSON.parse(rawData);
                    console.log("[DEBUG] Hydrating challenges for chunk. Count:", questions.length);

                    anchor.innerHTML = questions.map((q, idx) => {
                        const options = q.options || [];
                        const isLong = options.some(opt => (opt.text || opt).length > 30);

                        // Detailed Logging Group
                        console.groupCollapsed(`[MIRON_CHALLENGE] #${idx + 1} - ${q.id || 'No ID'}`);
                        console.log("Raw Meta Source:", q.meta_source);

                        // Metadata Parsing & Phrasing Logic
                        const meta = q.meta_source || {};
                        let sourceText = "From General Academic Archive";

                        if (meta.university) {
                            sourceText = `These questions are from ${meta.university}`;
                            if (meta.date || meta.type) {
                                const details = [meta.date, meta.type].filter(Boolean).join(' ');
                                sourceText += `, ${details}`;
                            } 
                        } else {
                            console.warn("Missing University Metadata - Using Fallback");
                        }

                        console.log("Final Display String:", sourceText);
                        console.groupEnd();

                        return `
                            <div class="miron-question-card">
                                <div class="q-header">
                                    <div class="miron-orb-mini"></div>
                                    <span class="q-label">Miron Challenge</span>
                                    <span class="q-points-badge">+5 Linkoins</span>
                                </div>
                                <div class="q-source-attribution">
                                    <i class="fa-solid fa-graduation-cap"></i>
                                    <span>${sourceText}</span>
                                </div>
                                <div class="q-text">${q.text}</div>
                                <div class="q-options ${isLong ? 'vertical-layout' : ''}">
