const handleIframeLoad = (e) => {
    console.group("%c[READER_DIAGNOSTICS] Iframe Initialization Started", "background: #1a1a1a; color: #42d7b8; font-weight: bold; padding: 4px;");
    const iframe = e.target;
    iframeRef.current = iframe;

    setTimeout(() => {
        try {
            const doc = iframe.contentDocument || iframe.contentWindow.document;
            if (!doc) {
                console.error("[READER_DIAGNOSTICS] FATAL: Access to Iframe Document denied!");
                return;
            }

            const docBody = doc.body;
            const docEl = doc.documentElement;

            // 1. Reset Iframe Environment
            docBody.style.margin = '0';
            docBody.style.padding = '0';
            docBody.style.overflow = 'visible'; // CRITICAL: Allow growth
            docEl.style.overflow = 'visible';

            // 2. Measure Native Content Pre-Injection
            const preH = Math.max(docBody.scrollHeight, docEl.scrollHeight);
            console.log(`[READER_DIAGNOSTICS] Content Height (Pre-Injection): ${preH}px`);

            // 3. Inject CSS Theme & Question Styles
            const baseFontSize = 22; 
            const style = doc.createElement('style');
            style.textContent = `
                @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@500;700&display=swap');
                @import url('https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css');

                body { transition: background-color 0.3s ease; min-height: 100vh; }
                body.theme-dark { background-color: #121212 !important; color: #d0d0d0 !important; }
                body.theme-sepia { background-color: #f4ecd8 !important; color: #5b4636 !important; }

                .miron-portal-container {
                    display: block !important;
                    visibility: visible !important;
                    opacity: 1 !important;
                    width: 90% !important;
                    margin: 4em auto !important;
                    font-family: 'Poppins', sans-serif;
                    font-size: ${baseFontSize}px; 
                    position: relative;
                    z-index: 999;
                    box-sizing: border-box;
                    color: inherit;
                }

                .miron-question-card {
                    margin-bottom: 3.5em;
                    padding: 1.5em;
                    background: rgba(128,128,128,0.03);
                    border-radius: 1.2em;
                    border: 1px solid rgba(128,128,128,0.1);
                }

                .q-header { display: flex; align-items: center; gap: 0.8em; margin-bottom: 1.2em; }
                .miron-orb-mini { width: 1em; height: 1em; background: #42d7b8; border-radius: 50%; box-shadow: 0 0 15px #42d7b8; }
                .q-label { color: #42d7b8; font-weight: 700; text-transform: uppercase; font-size: 0.8em; letter-spacing: 0.1em; }
                .q-points-badge { margin-left: auto; opacity: 0.6; font-size: 0.7em; font-family: monospace; }
                .q-text { font-size: 1.15em; line-height: 1.5; margin-bottom: 1.5em; font-weight: 600; }

                .q-opt-btn {
                    width: 100%; text-align: left; padding: 1em 1.2em; margin-bottom: 0.6em;
                    background: rgba(128,128,128,0.06); border: 1px solid rgba(128,128,128,0.15);
                    border-radius: 0.8em; color: inherit; cursor: pointer; transition: 0.2s;
                    font-size: 0.9em; font-family: inherit;
                }

                .q-opt-btn.selected {
                    background: rgba(66, 215, 184, 0.1); border-color: #42d7b8;
                    box-shadow: 0 4px 15px rgba(66, 215, 184, 0.2);
                }

                .q-submit {
                    display: none; width: 100%; margin-top: 1.5em; padding: 1em; 
                    background: #42d7b8; color: #000; border: none; border-radius: 50px;
                    font-weight: 700; font-size: 0.85em; text-transform: uppercase;
                    letter-spacing: 1px; cursor: pointer;
                }

                .miron-question-card:has(.selected) .q-submit { display: block !important; }
            `;
            doc.head.appendChild(style);

            // 4. Hydrate Miron Challenges
            const anchors = doc.querySelectorAll('.miron-challenge-anchor');
            console.log(`[READER_DIAGNOSTICS] Detected ${anchors.length} challenge anchors.`);

            anchors.forEach((anchor, aIdx) => {
                try {
                    const rawData = anchor.getAttribute('data-questions');
                    if (!rawData) return;

                    const questions = JSON.parse(rawData);
                    console.log(`[READER_DIAGNOSTICS] Anchor ${aIdx}: Parsing ${questions.length} questions.`);

                    anchor.innerHTML = `
                        <div class="miron-portal-container">
                            ${questions.map((q, qIdx) => `
                                <div class="miron-question-card">
                                    <div class="q-header">
                                        <div class="miron-orb-mini"></div>
                                        <span class="q-label">Miron Challenge</span>
                                        <span class="q-points-badge">+5 Linkoins</span>
                                    </div>
                                    <div class="q-text">${q.text}</div>
                                    <div class="q-options">
                                        ${q.options.map(opt => `
                                            <button class="q-opt-btn" onclick="this.parentElement.querySelectorAll('.q-opt-btn').forEach(b=>b.classList.remove('selected')); this.classList.add('selected');">${opt.text || opt}</button>
                                        `).join('')}
                                    </div>
                                    <button class="q-submit" onclick="this.innerText='CORRECT +5'; this.style.background='#b1d34b';">Check Understanding</button>
                                </div>
                            `).join('')}
                        </div>
                    `;
                    console.log(`[READER_DIAGNOSTICS] Anchor ${aIdx}: Injection complete.`);
                } catch (e) {
                    console.error(`[READER_DIAGNOSTICS] Anchor ${aIdx}: Hydration Error:`, e);
                }
            });

            // 5. Final Measure AFTER Mutation
            const postW = Math.max(docBody.scrollWidth, docEl.scrollWidth);
            const postH = Math.max(docBody.scrollHeight, docEl.scrollHeight);

            console.log(`[READER_DIAGNOSTICS] Final Dimensions: ${postW}px x ${postH}px`);

            contentDims.current = { width: postW, height: postH };
            if (layerRef.current) {
                layerRef.current.style.width = `${postW}px`;
                layerRef.current.style.height = `${postH}px`;
            }

            // Adjust viewport to fit width
            const vw = window.innerWidth;
            minScaleLimit.current = vw / postW;
            state.current.scale = minScaleLimit.current;

            doc.body.className = `theme-${currentTheme}`;
            console.groupEnd();

