                    // Rule 2: Bound to Page (Find closest container that is NOT the body)
                    const pageBoundary = targetElement.closest('.page, .page-container, .text-container') || docBody;

                    const sentenceRange = findSentenceRange(doc, targetNode, range.startOffset, pageBoundary);
                    if (sentenceRange) {
