            if (Math.abs(v.x) < 0.5) v.x = 0;
            if (Math.abs(v.y) < 0.5) v.y = 0;

            if (v.x !== 0 || v.y !== 0) {
                v.x *= CONFIG.friction;
                v.y *= CONFIG.friction;
                state.current.x += v.x;
                state.current.y += v.y;
            }
        }

