                ctxMenuRef.current.style.top = `${newY}px`;
                dragOffset.current.lastCtxX = newX; dragOffset.current.lastCtxY = newY;
            }
        };

        const handlePopoverEnd = () => {
            if (isDraggingPopover && dragOffset.current.lastX !== undefined) {
                setMironInsight(prev => ({
                    ...prev, 
                    x: dragOffset.current.lastX, 
                    y: dragOffset.current.lastY 
                }));
            }
            setIsDraggingPopover(false);
        };

        const handleCtxEnd = () => {
            if (isDraggingCtx && dragOffset.current.lastCtxX !== undefined) {
                setContextMenu(prev => ({ ...prev, x: dragOffset.current.lastCtxX, y: dragOffset.current.lastCtxY }));
            }
            setIsDraggingCtx(false);
        };

        if (isDraggingPopover) {
            window.addEventListener('mousemove', handleMove);
            window.addEventListener('mouseup', handlePopoverEnd);
            window.addEventListener('touchmove', handleMove, { passive: false });
            window.addEventListener('touchend', handlePopoverEnd);
        }
        if (isDraggingCtx) {
            window.addEventListener('mousemove', handleMove);
            window.addEventListener('mouseup', handleCtxEnd);
            window.addEventListener('touchmove', handleMove, { passive: false });
            window.addEventListener('touchend', handleCtxEnd);
        }

        return () => {
            window.removeEventListener('mousemove', handleMove);
            window.removeEventListener('mouseup', handlePopoverEnd);
            window.removeEventListener('mouseup', handleCtxEnd); // Add specific handler for mouseup end
            window.removeEventListener('touchmove', handleMove);
            window.removeEventListener('touchend', handlePopoverEnd);
            window.removeEventListener('touchend', handleCtxEnd); // Add specific handler for touchend end
        };
    }, [isDraggingPopover, isDraggingCtx, mironInsight, contextMenu]);

    const changeHighlightColor = (color) => {
        // In real app, we'd persist this or pass it to iframe to re-render custom highlights
        // For now, visual feedback that color was clicked
        console.log("Color changed to:", color);
        // We could inject CSS into iframe to change ::highlight(sentence-focus) color
        if (iframeRef.current) {
            const doc = iframeRef.current.contentDocument;
            const style = doc.getElementById('dynamic-highlight-style') || doc.createElement('style');
            style.id = 'dynamic-highlight-style';
            style.textContent = `::highlight(sentence-focus) { background-color: ${color}; color: #000; }`;
            if (!style.isConnected) doc.head.appendChild(style);
        }
    };

    const onSliderInput = (e) => {
        const val = parseFloat(e.target.value);
        // We reverse the math: calculate Y based on unscaled percentage
        const unscaledTotalH = contentDims.current.height;
        const viewHeight = window.innerHeight / state.current.scale;
        const maxScroll = Math.max(1, unscaledTotalH - viewHeight);

        const targetUnscaledY = (val / 100) * maxScroll;

        // Apply back to state (negate because Y is negative for scrolling down)
        state.current.y = -(targetUnscaledY * state.current.scale);
        velocity.current = { x: 0, y: 0 }; // Stop momentum
    };

    // Event Handlers
    useEffect(() => {
        const viewport = viewportRef.current;
        if (!viewport) return;

        // Start the render loop on mount
        requestRef.current = requestAnimationFrame(loop);

        const onTouchStart = (e) => {
            if (e.target.closest('#ui-layer') || e.target.closest('.fab-container')) return;
            e.preventDefault();

            const now = Date.now();
            // Check for swift consecutive scroll timing
            if (now - input.current.lastFlickTime < 600) {
                input.current.boostLevel = Math.min(input.current.boostLevel + 0.8, 5.0);
            } else {
                input.current.boostLevel = 1.0;
            }

            velocity.current = { x: 0, y: 0 };
            input.current.dragTotalDistance = 0;
            input.current.touchStartTime = now;

            if (e.touches.length === 1) {
                input.current.isDragging = true;
                input.current.startX = e.touches[0].clientX - state.current.x;
                input.current.startY = e.touches[0].clientY - state.current.y;
                input.current.lastX = e.touches[0].clientX;
                input.current.lastY = e.touches[0].clientY;
                input.current.lastTime = Date.now();
            } else if (e.touches.length === 2) {
                input.current.isDragging = false;
                input.current.initialPinchDist = Math.hypot(
                    e.touches[0].pageX - e.touches[1].pageX,
                    e.touches[0].pageY - e.touches[1].pageY
                );
                input.current.initialScale = state.current.scale;
            }
        };

        const onTouchMove = (e) => {
            if (e.target.closest('#ui-layer')) return;
            e.preventDefault();

            // NOTE: We do NOT call render() here. We only update data.
            // The loop() running on RAF will pick this up automatically.

            if (input.current.isDragging && e.touches.length === 1) {
                const x = e.touches[0].clientX;
                const y = e.touches[0].clientY;
                const dt = Date.now() - input.current.lastTime;

                input.current.dragTotalDistance += Math.hypot(x - input.current.lastX, y - input.current.lastY);

                // Update state
                state.current.x = x - input.current.startX;
                state.current.y = y - input.current.startY;

                // Immediate visual update to bypass RAF latency on start
                if (layerRef.current) {
                    layerRef.current.style.transform = `translate3d(${state.current.x}px, ${state.current.y}px, 0) scale(${state.current.scale})`;
                }

                // Calculate velocity for throw effect later
                if (dt > 0) {
                    velocity.current.x = (x - input.current.lastX) * CONFIG.velocityMult;
                    velocity.current.y = (y - input.current.lastY) * CONFIG.velocityMult;
                }

                input.current.lastX = x;
                input.current.lastY = y;
                input.current.lastTime = Date.now();
            } 
            else if (e.touches.length === 2) {
                input.current.dragTotalDistance += 100;
                const dist = Math.hypot(
                    e.touches[0].pageX - e.touches[1].pageX,
                    e.touches[0].pageY - e.touches[1].pageY
                );
                const cx = (e.touches[0].pageX + e.touches[1].pageX) / 2;
                const cy = (e.touches[0].pageY + e.touches[1].pageY) / 2;

                const ratio = dist / input.current.initialPinchDist;
                let newScale = input.current.initialScale * ratio;
                newScale = Math.max(minScaleLimit.current, Math.min(newScale, CONFIG.maxZoom));

                const contentX = (cx - state.current.x) / state.current.scale;
                const contentY = (cy - state.current.y) / state.current.scale;

                state.current.x = cx - (contentX * newScale);
                state.current.y = cy - (contentY * newScale);
                state.current.scale = newScale;
            }
        };

        const onTouchEnd = (e) => {
            if (e.target.closest('#ui-layer')) return;
            const duration = Date.now() - input.current.touchStartTime;

            if (input.current.isDragging && duration < 300 && input.current.dragTotalDistance < 10) {
                // PASS-THROUGH LOGIC
                const touch = e.changedTouches[0];
                const ix = (touch.clientX - state.current.x) / state.current.scale;
                const iy = (touch.clientY - state.current.y) / state.current.scale;

                const result = iframeRef.current?.contentWindow?.highlightAt?.(ix, iy);

                if (result && result.found && !result.isAction) {
                    const menuWidth = 260;
                    const menuHeight = 220;

                    // Convert Book coordinates to Screen coordinates
                    const sentenceTop = (result.rect.y * state.current.scale) + state.current.y;
                    const sentenceBottom = sentenceTop + (result.rect.height * state.current.scale);
                    const sentenceCenterX = (result.rect.x * state.current.scale) + state.current.x + (result.rect.width * state.current.scale / 2);

                    // Smart Y Positioning: Prefer Below, fallback to Above, strictly clamp to Viewport
                    let targetY = sentenceBottom + 15;

                    // If it hits the bottom of the screen, try above
                    if (targetY + menuHeight > window.innerHeight - 20) {
                        targetY = sentenceTop - menuHeight - 15;
                    }

                    // Failsafe: If trying to place above pushes it off the top (negative Y),
                    // force it back to below and let the user drag it if needed
                    if (targetY < 10) {
                        targetY = sentenceBottom + 15;
                    }

                    setContextMenu({
                        x: Math.max(10, Math.min(window.innerWidth - menuWidth - 10, sentenceCenterX - (menuWidth / 2))),
                        y: Math.max(10, Math.min(window.innerHeight - menuHeight - 20, targetY)),
                        text: result.text
                    });
                } else {
                    // Clicked whitespace
                    iframeRef.current?.contentWindow?.CSS?.highlights?.clear();
                    setContextMenu(null);
                }
            }

            if (input.current.isDragging && e.touches.length === 0) {
                input.current.isDragging = false;

                // Apply Accelerated Momentum if it was a flick
                const duration = Date.now() - input.current.touchStartTime;
                if (duration < 250 && input.current.dragTotalDistance > 20) {
                    input.current.lastFlickTime = Date.now();
                    velocity.current.x *= input.current.boostLevel;
                    velocity.current.y *= input.current.boostLevel;
                } else {
                    // Not a flick (slow drag), reset boost
                    input.current.boostLevel = 1.0;
                    input.current.lastFlickTime = 0;
                }
            }
        };

        // Mouse Fallbacks (Simplified for brevity, logic remains same)
        const onMouseDown = (e) => {
            if(e.target.closest('#ui-layer')) return;
            input.current.isDragging = true;
            input.current.dragTotalDistance = 0;
            input.current.touchStartTime = Date.now();
            input.current.startX = e.clientX - state.current.x;
            input.current.startY = e.clientY - state.current.y;
            input.current.lastX = e.clientX;
            input.current.lastY = e.clientY;
        };

        const onMouseMove = (e) => {
            if (input.current.isDragging) {
                e.preventDefault();
                input.current.dragTotalDistance += Math.hypot(e.clientX - input.current.lastX, e.clientY - input.current.lastY);
                input.current.lastX = e.clientX;
                input.current.lastY = e.clientY;
                state.current.x = e.clientX - input.current.startX;
                state.current.y = e.clientY - input.current.startY;
            }
        };

        const onMouseUp = (e) => {
            if (input.current.isDragging) {
                const duration = Date.now() - input.current.touchStartTime;
                if (duration < 300 && input.current.dragTotalDistance < 5) {
                    // Mouse Pass-through
                    const ix = (e.clientX - state.current.x) / state.current.scale;
                    const iy = (e.clientY - state.current.y) / state.current.scale;

                    const result = iframeRef.current?.contentWindow?.highlightAt?.(ix, iy);

                    if (result && result.found && !result.isAction) {
                        const menuX = (result.rect.x * state.current.scale) + state.current.x + (result.rect.width * state.current.scale / 2);
                        const menuY = (result.rect.y * state.current.scale) + state.current.y;
                        setContextMenu({ x: menuX, y: menuY, text: result.text });
                    } else if (!result || !result.found) {
                        iframeRef.current?.contentWindow?.CSS?.highlights?.clear();
                        setContextMenu(null);
                    }
                }
                input.current.isDragging = false;
            }
        };

        const onWheel = (e) => {
            e.preventDefault();
            if (e.ctrlKey) {
                let s = state.current.scale - e.deltaY * 0.01;
                state.current.scale = Math.max(minScaleLimit.current, Math.min(s, CONFIG.maxZoom));
            } else {
                state.current.y -= e.deltaY;
                state.current.x -= e.deltaX;
            }
        };

        viewport.addEventListener('touchstart', onTouchStart, { passive: false });
        viewport.addEventListener('touchmove', onTouchMove, { passive: false });
        viewport.addEventListener('touchend', onTouchEnd);
        viewport.addEventListener('mousedown', onMouseDown);
        window.addEventListener('mousemove', onMouseMove);
        window.addEventListener('mouseup', onMouseUp);
        viewport.addEventListener('wheel', onWheel, { passive: false });

        return () => {
            viewport.removeEventListener('touchstart', onTouchStart);
            viewport.removeEventListener('touchmove', onTouchMove);
            viewport.removeEventListener('touchend', onTouchEnd);
            viewport.removeEventListener('mousedown', onMouseDown);
            window.removeEventListener('mousemove', onMouseMove);
            window.removeEventListener('mouseup', onMouseUp);
            viewport.removeEventListener('wheel', onWheel);
            if (requestRef.current) cancelAnimationFrame(requestRef.current);
        };
    }, []);

